#!/bin/bash
# This file was generated by Cursor AI on 2026-05-04.

set -euo pipefail

usage() {
    echo "Usage: $0 <timeout> <memout> <num_jobs> <num_gurobi_threads> <input_file_list>" >&2
    exit 1
}

if [ "$#" -ne 5 ]; then
    usage
fi

TIMEOUT="$1"
MEMOUT="$2"
NUM_JOBS="$3"
NUM_GUROBI_THREADS="$4"
INPUT_FILE_LIST="$5"

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"

"$SCRIPT_DIR/benchmark.sh" \
  --input-file-list "$INPUT_FILE_LIST" \
  --output-json "/opt/benchmarks/results/greedy_ac.json" \
  --timeout "$TIMEOUT" \
  --memout "$MEMOUT" \
  --num-jobs "$NUM_JOBS" \
  --extraction-method "greedy" \
  --multi-arity \
  --assoc-comm \
  --num-gurobi-threads "$NUM_GUROBI_THREADS"
